// Per-section native bench for the RWKV-7 BATCHED (width-axis) kernels at the
// 2.9B shape (hidden 2560, 40 heads × 64, ffn_inner 10240) — the marginal-lane
// cost model behind the K-series (kill the wasm batch kernel's marginal-lane
// cost). Times, per section, SOLO vs width-{1,2,4,8} batch:
//
//   timemix     stream_layer_timemix (solo) vs stream_layer_timemix_batch
//   channelmix  stream_layer_channelmix (solo) vs stream_layer_channelmix_batch
//   layer       both halves (the unit the fleet hops per station per token)
//   f16 codec   put_f16s/take_f16s over one lane's full 2560-shape layer state
//               (wkv 163,840 + shift/channel/v_first 3×2,560 f32) — exactly the
//               per-lane, per-layer `export/import_batch_layer_state_f16` work
//
// marginal(n) = (T_batch(n) − T_batch(1)) / ((n−1) · T_batch(1)) — the cost of
// ADDING a lane relative to the first (the width-axis amortization target;
// `Gnosis.WarpBatchAmortization.sharedCost`). Native numbers are a proxy for
// alloc/WKV/codec structure (the native matvec dequants per row, not the wasm
// fused-Q8 kernel); the wasm marginal is measured by the V8 bench mode of
// `apps/vcpu-tick/src/infer/rwkv7-batch-wave.smoke.ts`.
//
// Weights are synthetic (deterministic sin fill, F32-resident) — layer 1 is the
// benched layer so the v-lora blend (skipped at layer 0) is included, matching
// the steady-state per-layer cost.
//
// Run: cargo run --release -p distributed-inference --bin bench-batch-marginal

use distributed_inference::f16_codec::{put_f16s, take_f16s};
use distributed_inference::loader::{KnotConfig, OwnedBytes, TensorInfo, WeightBackend};
use distributed_inference::model_rwkv7::{RWKV7Config, RWKV7LayerState, RWKV7Pipeline};
use std::any::Any;
use std::collections::HashMap;
use std::sync::Arc;
use std::time::Instant;

// ── 2.9B-shaped synthetic dims (head_dim forces to 64 in from_knot: 2560 % 64 == 0) ──
const D: usize = 2560;
const N_HEADS: usize = 40;
const HEAD_SIZE: usize = 64;
const LRW: usize = 64;
const GATE_INNER: usize = 128;
const FFN_INNER: usize = 10240;
const VOCAB: usize = 512; // small: the lm_head is not the section under test
const LAYERS: usize = 2; // layer 1 is benched (includes the v-lora blend)
const BENCH_LAYER: usize = 1;

const WIDTHS: [usize; 4] = [1, 2, 4, 8];
const REPS: usize = 9;

/// Arc-backed mock (same tensor names/fill as tests/rwkv7_integration_test.rs
/// MockBackend, but fetch clones an Arc, not the bytes — a fetch must not cost
/// a 105 MB memcpy or the per-call `build_layer_weights_part` would swamp the
/// kernel being measured).
struct ArcBackend {
    store: HashMap<String, Arc<Vec<u8>>>,
}

impl ArcBackend {
    fn new() -> Self {
        Self { store: HashMap::new() }
    }
    fn insert_f32(&mut self, name: &str, v: Vec<f32>) {
        let bytes: Vec<u8> = v.iter().flat_map(|f| f.to_le_bytes()).collect();
        self.store.insert(name.to_string(), Arc::new(bytes));
    }
    fn fill(&mut self, name: &str, n: usize, seed: f32) {
        let v: Vec<f32> = (0..n).map(|i| (i as f32 * seed).sin() * 0.05).collect();
        self.insert_f32(name, v);
    }
    fn fill_ones(&mut self, name: &str, n: usize) {
        self.insert_f32(name, vec![1.0f32; n]);
    }
}

impl WeightBackend for ArcBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        self.store
            .get(name)
            .or_else(|| self.store.get(bare))
            .map(|a| OwnedBytes::Owned(a.clone()))
            .ok_or_else(|| format!("ArcBackend: missing {name:?}"))
    }
    fn has_tensor(&self, name: &str) -> bool {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        self.store.contains_key(name) || self.store.contains_key(bare)
    }
    fn as_any(&self) -> &dyn Any {
        self
    }
    fn tensor_info(&self, name: &str) -> Option<TensorInfo> {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        let a = self.store.get(name).or_else(|| self.store.get(bare))?;
        Some(TensorInfo {
            offset: 0,
            length: a.len() as u64,
            tensor_type: "F32".to_string(),
            shape: None,
        })
    }
}

fn build_backend() -> Arc<dyn WeightBackend> {
    let mut b = ArcBackend::new();
    b.fill("token_embd_weight", VOCAB * D, 0.01);
    b.fill_ones("output_norm_weight", D);
    b.insert_f32("output_norm_bias", vec![0.0f32; D]);
    b.fill("output_weight", VOCAB * D, 0.02);
    for l in 0..LAYERS {
        let n = |s: &str| format!("blk_{l}_{s}");
        b.fill_ones(&n("ln1_weight"), D);
        b.insert_f32(&n("ln1_bias"), vec![0.0f32; D]);
        b.fill_ones(&n("ln2_weight"), D);
        b.insert_f32(&n("ln2_bias"), vec![0.0f32; D]);
        for tag in &["mix_r", "mix_w", "mix_k", "mix_v", "mix_a", "mix_g"] {
            b.fill(&n(&format!("rwkv_{tag}")), D, 0.05);
        }
        b.fill(&n("rwkv_r_weight"), D * D, 0.03);
        b.fill(&n("rwkv_k_weight"), D * D, 0.03);
        b.fill(&n("rwkv_v_weight"), D * D, 0.03);
        b.fill(&n("rwkv_o_weight"), D * D, 0.03);
        b.fill(&n("rwkv_w0"), D, -0.5);
        b.fill(&n("rwkv_w1"), LRW * D, 0.02);
        b.fill(&n("rwkv_w2"), D * LRW, 0.02);
        b.fill(&n("rwkv_a0"), D, 0.0);
        b.fill(&n("rwkv_a1"), LRW * D, 0.02);
        b.fill(&n("rwkv_a2"), D * LRW, 0.02);
        b.fill(&n("rwkv_v0"), D, 0.0);
        b.fill(&n("rwkv_v1"), LRW * D, 0.02);
        b.fill(&n("rwkv_v2"), D * LRW, 0.02);
        b.fill(&n("rwkv_k_k"), D, 0.5);
        b.fill(&n("rwkv_k_a"), D, 0.5);
        b.fill(&n("rwkv_r_k"), D, 0.1);
        b.fill(&n("rwkv_g1_weight"), GATE_INNER * D, 0.03);
        b.fill(&n("rwkv_g2_weight"), D * GATE_INNER, 0.03);
        b.fill_ones(&n("rwkv_ln_x_weight"), D);
        b.insert_f32(&n("rwkv_ln_x_bias"), vec![0.0f32; D]);
        b.fill(&n("ffn_mix_k"), D, 0.05);
        b.fill(&n("ffn_k_weight"), FFN_INNER * D, 0.02);
        b.fill(&n("ffn_v_weight"), D * FFN_INNER, 0.02);
    }
    Arc::new(b)
}

fn knot_config() -> KnotConfig {
    serde_json::from_str(&format!(
        r#"{{
        "hidden_dim": {D}, "num_layers": {LAYERS}, "num_heads": {N_HEADS},
        "num_kv_heads": {N_HEADS}, "head_dim": {HEAD_SIZE},
        "intermediate_size": {FFN_INNER}, "vocab_size": {VOCAB},
        "arch": "rwkv7",
        "rwkv_n_heads": {N_HEADS},
        "rwkv_low_rank_w": {LRW}, "rwkv_low_rank_a": {LRW}, "rwkv_low_rank_v": {LRW},
        "rwkv_gate_inner": {GATE_INNER}
    }}"#
    ))
    .unwrap()
}

fn vec_fill(n: usize, seed: f32) -> Vec<f32> {
    (0..n).map(|i| (i as f32 * seed).sin() * 0.05).collect()
}

/// Median-of-REPS wall time (ms) for `f` (one untimed warmup first).
fn time_ms<F: FnMut()>(mut f: F) -> f64 {
    f(); // warmup: page/dequant caches, allocator high-water mark
    let mut samples = Vec::with_capacity(REPS);
    for _ in 0..REPS {
        let t = Instant::now();
        f();
        samples.push(t.elapsed().as_secs_f64() * 1e3);
    }
    samples.sort_by(|a, b| a.partial_cmp(b).unwrap());
    samples[REPS / 2]
}

fn marginal(t_n: f64, t_1: f64, n: usize) -> f64 {
    (t_n - t_1) / ((n as f64 - 1.0) * t_1)
}

struct Row {
    name: &'static str,
    per_width_ms: Vec<f64>, // indexed like WIDTHS
    solo_ms: f64,
}

fn print_table(rows: &[Row]) {
    println!(
        "\n{:<12} {:>9} {:>9} {:>9} {:>9} {:>9} {:>7} {:>7}",
        "section", "solo ms", "w1 ms", "w2 ms", "w4 ms", "w8 ms", "mg@4", "mg@8"
    );
    for r in rows {
        println!(
            "{:<12} {:>9.2} {:>9.2} {:>9.2} {:>9.2} {:>9.2} {:>6.2}x {:>6.2}x",
            r.name,
            r.solo_ms,
            r.per_width_ms[0],
            r.per_width_ms[1],
            r.per_width_ms[2],
            r.per_width_ms[3],
            marginal(r.per_width_ms[2], r.per_width_ms[0], 4),
            marginal(r.per_width_ms[3], r.per_width_ms[0], 8),
        );
    }
}

fn main() {
    println!(
        "bench-batch-marginal: D={D} heads={N_HEADS}x{HEAD_SIZE} ffn={FFN_INNER} layer={BENCH_LAYER} reps={REPS} (median)"
    );
    let cfg_json = knot_config();
    let backend = build_backend();
    println!("backend built");
    let mut pipeline = RWKV7Pipeline::from_knot(&cfg_json, backend);
    let cfg = RWKV7Config::from_knot(&cfg_json);
    assert_eq!(cfg.n_heads, N_HEADS);
    assert_eq!(cfg.head_size, HEAD_SIZE);
    println!("pipeline resident");

    let x0 = vec_fill(D, 0.017);
    let vf0 = vec_fill(D, 0.023);

    // ── solo halves (per-lane reference cost) ────────────────────────────────
    // stream state: seed residual + v_first, advance the benched layer only.
    pipeline.set_stream_x(x0.clone());
    pipeline.set_stream_v_first(vf0.clone());
    let solo_tm = time_ms(|| {
        pipeline.set_stream_x(x0.clone());
        pipeline.set_stream_v_first(vf0.clone());
        pipeline.stream_layer_timemix(BENCH_LAYER);
    });
    let solo_cm = time_ms(|| {
        pipeline.set_stream_x(x0.clone());
        pipeline.stream_layer_channelmix(BENCH_LAYER);
    });
    let solo_layer = time_ms(|| {
        pipeline.set_stream_x(x0.clone());
        pipeline.set_stream_v_first(vf0.clone());
        pipeline.stream_layer_timemix(BENCH_LAYER);
        pipeline.stream_layer_channelmix(BENCH_LAYER);
    });
    println!("solo done: timemix {solo_tm:.2}ms channelmix {solo_cm:.2}ms layer {solo_layer:.2}ms");

    // ── batched halves per width ─────────────────────────────────────────────
    let mut tm_w = Vec::new();
    let mut cm_w = Vec::new();
    let mut layer_w = Vec::new();
    for &n in &WIDTHS {
        let mut xs: Vec<Vec<f32>> = (0..n).map(|k| vec_fill(D, 0.017 + 0.001 * k as f32)).collect();
        let mut vfs: Vec<Vec<f32>> = (0..n).map(|k| vec_fill(D, 0.023 + 0.001 * k as f32)).collect();
        let mut states: Vec<RWKV7LayerState> = (0..n)
            .map(|_| RWKV7LayerState::new(D, N_HEADS, HEAD_SIZE))
            .collect();
        tm_w.push(time_ms(|| {
            pipeline.stream_layer_timemix_batch(BENCH_LAYER, &mut xs, &mut vfs, &mut states);
        }));
        cm_w.push(time_ms(|| {
            pipeline.stream_layer_channelmix_batch(BENCH_LAYER, &mut xs, &mut states);
        }));
        layer_w.push(time_ms(|| {
            pipeline.stream_layer_timemix_batch(BENCH_LAYER, &mut xs, &mut vfs, &mut states);
            pipeline.stream_layer_channelmix_batch(BENCH_LAYER, &mut xs, &mut states);
        }));
        println!(
            "width {n}: timemix {:.2}ms channelmix {:.2}ms layer {:.2}ms",
            tm_w.last().unwrap(),
            cm_w.last().unwrap(),
            layer_w.last().unwrap()
        );
    }

    // ── f16 state codec: one lane's FULL layer state, both directions ───────
    // (wkv [n_heads·hs·hs] + shift_x + channel_state + v_first — the exact
    // per-lane/per-layer export/import_batch_layer_state_f16 frames.)
    let state_wkv = vec_fill(N_HEADS * HEAD_SIZE * HEAD_SIZE, 0.011);
    let state_small = vec_fill(D, 0.013);
    let mut frame: Vec<u8> = Vec::new();
    let enc = |frame: &mut Vec<u8>| {
        frame.clear();
        put_f16s(frame, &state_wkv);
        put_f16s(frame, &state_small);
        put_f16s(frame, &state_small);
        put_f16s(frame, &state_small);
    };
    let export_ms = time_ms(|| enc(&mut frame));
    enc(&mut frame);
    let mut out: Vec<f32> = Vec::new();
    let import_ms = time_ms(|| {
        let mut off = 0usize;
        take_f16s(&frame, &mut off, &mut out);
        take_f16s(&frame, &mut off, &mut out);
        take_f16s(&frame, &mut off, &mut out);
        take_f16s(&frame, &mut off, &mut out);
    });
    let n_f32 = N_HEADS * HEAD_SIZE * HEAD_SIZE + 3 * D;
    println!(
        "\nf16 codec (per lane per layer, {n_f32} f32): export {export_ms:.3}ms import {import_ms:.3}ms (roundtrip {:.3}ms)",
        export_ms + import_ms
    );

    let rows = vec![
        Row { name: "timemix", solo_ms: solo_tm, per_width_ms: tm_w },
        Row { name: "channelmix", solo_ms: solo_cm, per_width_ms: cm_w },
        Row { name: "layer", solo_ms: solo_layer, per_width_ms: layer_w },
    ];
    print_table(&rows);
    println!(
        "\nmg@n = (T(n) - T(1)) / ((n-1) * T(1)) — marginal cost of one added lane vs the first."
    );
    println!(
        "codec adds {:.2}ms per lane per layer on the shard wire (not in the table rows above).",
        export_ms + import_ms
    );
}
